INSERT INTO `memory_entry`
(`title`, `summary`, `content`, `memory_date`, `cover_image_url`, `cover_storage_path`, `mood_tags`, `is_featured`, `visibility`, `sort_order`, `favorite_count`)
VALUES
('把海边的小画递过来的晚上','她把蓝色海边插画举到镜头前，像把刚画好的好心情认真递过来给你看。','那天书桌边很安静，灯没有特别亮，桌面上的东西也还是画到一半的样子。\n\n她坐在那里，把刚完成的海边插画轻轻举起来，没有夸张地展示，只是很自然地想让人看看她今晚认真画出来的这一点小小成果。蓝色的海、浅浅的天，还有她举起来时那种带一点期待又带一点害羞的神情，让整张照片一下子有了温度。\n\n后来再回头看，会觉得被记住的不只是那幅画本身，而是她愿意把自己刚刚完成的东西分享出来的那一瞬间。那种不张扬、却很真诚的开心，特别适合被放进回忆手账里。','2026-06-27','/uploads/photos/226_小可_书桌蓝色海边插画展示照.png','photos/226_小可_书桌蓝色海边插画展示照.png','书桌,插画,夜晚',1,'PUBLIC',390,NULL),
('草地上慢慢坐下来的下午','她坐在草地上，裙摆铺开得很轻，像把下午的风也一起留在了身边。','那天下午的光不急不慢，草地也很安静，连风吹过来的时候都带着一点轻轻软软的味道。\n\n她穿着洛丽塔短裙坐在草地上，裙摆自然铺开，动作并不夸张，却很容易让人一下子记住。不是因为刻意摆拍，而是那种坐下来之后，整个人都和周围的光线、草地、空气融在一起的感觉，太像一段会被反复翻看的夏日片段。\n\n我会想把这张留下来，是因为它很像小可偶尔露出来的另一种可爱。安静、轻盈，又有一点点像梦一样不真实，但偏偏就是这样的画面，会让人很想把那个下午好好收进手账里。','2026-06-28','/uploads/photos/230_小可_草地洛丽塔短裙坐姿照.png','photos/230_小可_草地洛丽塔短裙坐姿照.png','草地,洛丽塔,下午',1,'PUBLIC',400,NULL),
('毛绒睡衣里的晚安时间','白色毛绒睡衣把整个人都衬得很软，像今天终于可以安心停下来了。','晚上回到房间以后，很多事情都会慢慢安静下来，连说话的声音都会不自觉变轻一点。\n\n她穿着白色毛绒睡衣坐在床边，整个人都被那种软绵绵的质感包住了。没有什么很特别的动作，也没有刻意要表达什么，只是很自然地坐在那里，可就是会让人觉得，今天大概终于可以休息了。那种放下紧绷之后的小小松弛，比很多热闹的时刻都更打动人。\n\n这张照片适合写进手账，不是因为场景多复杂，而是因为它太像生活本身了。一天结束以后，能安安静静地待在熟悉的房间里，本来就是很值得被认真记住的小幸福。','2026-06-28','/uploads/photos/231_小可_卧室白色毛绒睡衣坐姿照.png','photos/231_小可_卧室白色毛绒睡衣坐姿照.png','居家,睡衣,晚安',1,'PUBLIC',410,NULL),
('海风把夏天吹得很近','海风和白色水手服都很轻，她靠近镜头时，像把夏天最明亮的那一点留住了。','海边的光总是比别的地方更容易让人心软一点。\n\n她穿着白色水手服站在海风里，靠近镜头的时候，眼神很安静，衣服和发丝却都被风轻轻带动着。那不是很用力的漂亮，反而像夏天自己走到了她身边，再顺手把最清澈的那一点光留在了照片里。整张图很亮，但不刺眼，像一段会被记住很久的好天气。\n\n后来我再看这张，想到的已经不只是海边，而是那种被夏天照亮的心情。人没有说很多话，可光线、风和她站在那里的样子，就已经足够把那天的温柔完整留住了。','2026-06-29','/uploads/photos/235_小可_海边白色水手服近景照.png','photos/235_小可_海边白色水手服近景照.png','海边,水手服,夏天',1,'PUBLIC',420,NULL),
('窗边再落下一次光','同样是窗边站着，这一张更像故事翻到下一页时，光和衣摆又轻轻落下来一次。','和室的光线总是有一种很特别的安静，好像连时间都会在这里慢一点。\n\n她穿着巫女服站在窗边，衣摆和袖口都被光线托得很轻。和前一张相比，这一张更像故事翻到下一页之后留下来的画面，没有刻意强调什么情绪，却偏偏因为太安静了，反而让人更想停下来多看一会儿。她站在那里的样子，很像一段旧故事里会被珍藏的片段。\n\n这类照片最适合写进回忆手账，因为它们不像日常那样直接，却会在之后某个时刻被重新想起。就像有些心动不是一下子说出来的，而是过后翻到这一页时，才发现原来当时已经被打动了。','2026-06-29','/uploads/photos/237_小可_和室巫女服窗边站姿照二.png','photos/237_小可_和室巫女服窗边站姿照二.png','和室,巫女服,窗边',0,'PUBLIC',430,NULL),
('把杆边把呼吸放稳的时刻','她扶着把杆站着，红色练功服把状态衬得很鲜明，像认真练习的一晚被稳稳记下。','舞蹈室里的灯光很亮，地板也会把动作和节奏都衬得更清楚。\n\n她站在把杆边，红色练功服把整个人的状态都提了起来。不是舞台上那种热烈的光，而是训练时很明确、很安静的认真。每一个动作都需要身体跟上，呼吸也要慢慢稳下来，所以这样的照片看起来会有一种特别扎实的力量，不张扬，却很难让人忽略。\n\n我想把这张放进手账，是因为它把小可身上那种认真对待一件事的样子留下来了。柔软并不意味着没有力度，很多时候，正是这种安静坚持的时刻，最值得被记住。','2026-06-29','/uploads/photos/239_小可_舞蹈室红色练功服把杆站姿照.png','photos/239_小可_舞蹈室红色练功服把杆站姿照.png','舞蹈室,练功,认真',0,'PUBLIC',440,NULL);
